#include <stdio.h>

float average(int a, int b) {
    return (float)(a + b) / (a - b);
}

int main() {
    int x = 5, y = 5;
    printf("Average: %.2f\n", average(x, y));
    return 0;
}

#include <stdio.h>

int sum(int n) {
    return n + sum(n - 1);
}

int main() {
    int num = 5;
    printf("Suma: %d\n", sum(num));
    return 0;
}
